import{_ as r,c as o,o as a,ag as d}from"./chunks/framework.XjE0kKti.js";const s="/gatewayweb/docs/assets/hub0020-list.B0NsckNb.png",n="/gatewayweb/docs/assets/hub0020-row-menu-config.DGt0aJvg.png",e="/gatewayweb/docs/assets/hub0020-row-menu-tools.Mleabb39.png",l="/gatewayweb/docs/assets/hub0020-performance.DEFjEU3R.png",T=JSON.parse('{"title":"实例管理","description":"","frontmatter":{},"headers":[],"relativePath":"modules/hub0020.md","filePath":"modules/hub0020.md","lastUpdated":1776841524000}'),i={name:"modules/hub0020.md"};function h(g,t,b,c,u,p){return a(),o("div",null,[...t[0]||(t[0]=[d('<h1 id="实例管理" tabindex="-1">实例管理 <a class="header-anchor" href="#实例管理" aria-label="Permalink to &quot;实例管理&quot;">​</a></h1><p>用于创建与维护<strong>网关实例</strong>：配置监听地址与端口、TLS、安全与性能参数，并执行实例的启动/停止、网关重载，以及导入/导出实例配置。适合在多实例、多环境下做统一管理与标准化交付。</p><p><img src="'+s+'" alt="实例管理：实例列表"></p><hr><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>一个<strong>网关实例</strong>通常对应一套独立的监听端口与运行参数（HTTP/HTTPS、TLS、连接与超时、限流/认证/跨域等）。本页侧重“实例维度”的生命周期与配置入口：</p><ul><li><strong>实例生命周期</strong>：新增、编辑、删除、启动、停止。</li><li><strong>配置变更生效</strong>：保存配置后可通过 <strong>网关重载</strong> 让实例重新加载配置（具体生效策略以后端实现与部署方式为准）。</li><li><strong>配置复用</strong>：通过导入/导出把实例及关联配置在环境之间迁移或做备份。</li></ul><hr><h2 id="访问入口" tabindex="-1">访问入口 <a class="header-anchor" href="#访问入口" aria-label="Permalink to &quot;访问入口&quot;">​</a></h2><p>侧栏 <strong>网关管理</strong> → <strong>实例管理</strong>。</p><hr><h2 id="查找与查看实例" tabindex="-1">查找与查看实例 <a class="header-anchor" href="#查找与查看实例" aria-label="Permalink to &quot;查找与查看实例&quot;">​</a></h2><h3 id="筛选条件" tabindex="-1">筛选条件 <a class="header-anchor" href="#筛选条件" aria-label="Permalink to &quot;筛选条件&quot;">​</a></h3><table tabindex="0"><thead><tr><th>条件</th><th>说明</th></tr></thead><tbody><tr><td>实例名称</td><td>按名称检索（占位提示为「请输入实例名称」）。</td></tr><tr><td>健康状态</td><td>全部、健康或不健康（通常与在线/离线心跳相关）。</td></tr><tr><td>活动状态</td><td>全部、活动或非活动。</td></tr></tbody></table><p>点击 <strong>查询</strong> 按条件加载列表；<strong>重置</strong> 清空条件并回到默认视图。</p><h3 id="列表字段-常见" tabindex="-1">列表字段（常见） <a class="header-anchor" href="#列表字段-常见" aria-label="Permalink to &quot;列表字段（常见）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>列</th><th>说明</th></tr></thead><tbody><tr><td>实例ID</td><td>实例唯一标识。</td></tr><tr><td>实例名称 / 实例描述</td><td>便于区分用途与环境。</td></tr><tr><td>绑定地址</td><td>监听的网卡地址，常见为 <code>0.0.0.0</code>（监听全部接口）。</td></tr><tr><td>HTTP端口 / HTTPS端口</td><td>实例对外提供服务的端口；HTTPS 端口通常在启用 TLS 后生效。</td></tr><tr><td>TLS</td><td>启用/禁用。</td></tr><tr><td>最大连接数</td><td>并发连接上限的关键指标。</td></tr><tr><td>健康状态</td><td>在线/离线（或健康/不健康）状态提示。</td></tr><tr><td>活动状态</td><td>活动/非活动。</td></tr></tbody></table><hr><h2 id="工具栏操作" tabindex="-1">工具栏操作 <a class="header-anchor" href="#工具栏操作" aria-label="Permalink to &quot;工具栏操作&quot;">​</a></h2><table tabindex="0"><thead><tr><th>操作</th><th>用途与说明</th></tr></thead><tbody><tr><td><strong>新建实例</strong></td><td>创建一个新的网关实例。</td></tr><tr><td><strong>编辑</strong></td><td>编辑所选实例；若未选中行会提示先勾选/点击选择。</td></tr><tr><td><strong>删除</strong></td><td>二次确认后删除实例；删除不可恢复。</td></tr><tr><td><strong>导出配置</strong></td><td>导出当前所选实例的配置（Excel），用于备份或迁移。</td></tr><tr><td><strong>导入配置</strong></td><td>从 Excel 导入实例及关联配置，用于环境初始化或批量交付。</td></tr></tbody></table><hr><h2 id="右键菜单与常用动作" tabindex="-1">右键菜单与常用动作 <a class="header-anchor" href="#右键菜单与常用动作" aria-label="Permalink to &quot;右键菜单与常用动作&quot;">​</a></h2><p>在列表行上右键，可快速执行实例相关操作与进入配置入口。</p><p><img src="'+n+'" alt="实例管理：右键菜单（配置入口）"></p><p><img src="'+e+'" alt="实例管理：右键菜单（工具）"></p><h3 id="基础操作" tabindex="-1">基础操作 <a class="header-anchor" href="#基础操作" aria-label="Permalink to &quot;基础操作&quot;">​</a></h3><table tabindex="0"><thead><tr><th>菜单项</th><th>说明</th></tr></thead><tbody><tr><td>查看详情</td><td>查看实例完整配置（只读）。</td></tr><tr><td>编辑</td><td>打开编辑对话框并回显实例配置。</td></tr><tr><td>删除</td><td>删除实例（需二次确认）。</td></tr><tr><td>启动 / 停止</td><td>控制实例运行状态（需二次确认）。</td></tr><tr><td>网关重载</td><td>重新加载配置，常用于让变更尽快生效（需二次确认）。</td></tr></tbody></table><h3 id="全局配置-以实例为作用域" tabindex="-1">全局配置（以实例为作用域） <a class="header-anchor" href="#全局配置-以实例为作用域" aria-label="Permalink to &quot;全局配置（以实例为作用域）&quot;">​</a></h3><p>全局配置用于为单个实例配置安全与治理能力，常见入口包括：</p><ul><li><strong>IP访问控制</strong>：按客户端 IP 放行/拦截规则。</li><li><strong>User-Agent访问控制</strong>：按 UA 放行/拦截规则。</li><li><strong>API访问控制</strong>：按接口路径、方法或策略做访问控制（以界面为准）。</li><li><strong>域名访问控制</strong>：按 Host/域名做放行与限制。</li><li><strong>跨域配置</strong>：配置 CORS 相关响应头与策略。</li><li><strong>认证配置</strong>：配置认证方式与参数（如令牌校验等，以界面为准）。</li><li><strong>限流配置</strong>：配置限流策略与阈值（以界面为准）。</li></ul><p>这些配置通常与实例 ID 绑定；配置保存后，建议视情况执行 <strong>网关重载</strong> 或按发布策略等待生效。</p><h3 id="日志配置" tabindex="-1">日志配置 <a class="header-anchor" href="#日志配置" aria-label="Permalink to &quot;日志配置&quot;">​</a></h3><p><strong>日志配置</strong>用于控制网关访问日志的内容、输出目标与清理/预警策略。若实例尚未绑定日志配置，进入时会提示先创建或补齐日志配置（具体联动策略以当前环境为准）。</p><p>常见能力包括：</p><ul><li><strong>内容控制</strong>：是否记录请求体/响应体/请求头，最大报文大小等。</li><li><strong>输出目标</strong>：文件、数据库、MongoDB、Elasticsearch、ClickHouse 等（以界面选项为准）。</li><li><strong>清理与预警</strong>：保留天数、轮转策略、敏感字段脱敏与预警通道等。</li></ul><hr><h2 id="新建与编辑实例-表单概览" tabindex="-1">新建与编辑实例（表单概览） <a class="header-anchor" href="#新建与编辑实例-表单概览" aria-label="Permalink to &quot;新建与编辑实例（表单概览）&quot;">​</a></h2><p>实例表单通常按页签组织：<strong>基本信息</strong>、<strong>TLS配置</strong>、<strong>性能配置</strong>、<strong>其它</strong>。建议先完成基本信息与端口，再按需启用 TLS 与治理能力。</p><h3 id="基本信息-常见" tabindex="-1">基本信息（常见） <a class="header-anchor" href="#基本信息-常见" aria-label="Permalink to &quot;基本信息（常见）&quot;">​</a></h3><ul><li><strong>实例名称</strong>：建议包含环境与用途（如 <code>prod-gw-01</code>）。</li><li><strong>绑定地址</strong>：默认 <code>0.0.0.0</code>；若需要限制网卡，可填具体地址。</li><li><strong>HTTP端口 / HTTPS端口</strong>：按规划填写，避免与宿主端口冲突。</li><li><strong>自动启动</strong>：决定实例是否在系统启动或托管流程中自动拉起（含义以部署方式为准）。</li></ul><h3 id="tls-配置-常见" tabindex="-1">TLS 配置（常见） <a class="header-anchor" href="#tls-配置-常见" aria-label="Permalink to &quot;TLS 配置（常见）&quot;">​</a></h3><ul><li><strong>启用TLS</strong>：开启 HTTPS/TLS 加密传输。</li><li><strong>TLS版本</strong>：建议至少启用 TLS 1.2；旧版本不安全。</li><li><strong>证书/私钥</strong>：上传证书与私钥（支持常见扩展名），或按系统存储策略保存到数据库。</li></ul><h3 id="性能配置-常见" tabindex="-1">性能配置（常见） <a class="header-anchor" href="#性能配置-常见" aria-label="Permalink to &quot;性能配置（常见）&quot;">​</a></h3><ul><li><strong>最大连接数</strong>、<strong>工作协程数</strong>、各类超时（读/写/空闲）、请求头上限等会影响吞吐与资源占用；建议按压测结果逐步调整。</li></ul><p><img src="'+l+'" alt="实例管理：性能配置页签"></p><h4 id="典型问题-客户端读取超时与-报文被拦截" tabindex="-1">典型问题：客户端读取超时与“报文被拦截” <a class="header-anchor" href="#典型问题-客户端读取超时与-报文被拦截" aria-label="Permalink to &quot;典型问题：客户端读取超时与“报文被拦截”&quot;">​</a></h4><p>当出现“客户端读取超时”“请求卡住后被断开”“大报文/慢上传容易失败”等现象时，通常需要优先检查本页的超时与限额参数（并与上游 LB、WAF、客户端 SDK 的超时配置一起对齐）。</p><table tabindex="0"><thead><tr><th>现象</th><th>常见原因</th><th>建议调整方向</th></tr></thead><tbody><tr><td><strong>客户端读取超时</strong>（请求发送到一半或刚建立连接就断开）</td><td><strong>读取超时(ms)</strong> 过小，慢网络/大请求体导致服务端在读取请求头/请求体阶段超时</td><td>适当<strong>增大读取超时</strong>；同时检查上游是否有更短的超时导致提前断链</td></tr><tr><td><strong>响应写回超时</strong>（服务端已有处理但客户端收不到完整响应）</td><td><strong>写入超时(ms)</strong> 过小，或下游响应慢/大响应体</td><td>适当<strong>增大写入超时</strong>；排查下游耗时与响应体大小</td></tr><tr><td><strong>长连接空闲后被断开</strong>（间歇性请求、SSE/长轮询）</td><td><strong>空闲超时(ms)</strong> 过小，或 Keep-Alive 配置不匹配</td><td>适当<strong>增大空闲超时</strong>；确认 <strong>HTTP Keep-Alive / TCP Keep-Alive</strong> 开关策略与上游一致</td></tr><tr><td><strong>大请求头被拒</strong>（Cookie/鉴权头很大，出现 4xx/连接中断等）</td><td><strong>最大请求头大小(字节)</strong> 过小</td><td>评估风险后<strong>增大请求头上限</strong>；同时治理过大的 Cookie/Header</td></tr><tr><td><strong>高并发下排队/拒绝连接</strong></td><td><strong>最大连接数</strong> 或 <strong>最大工作协程数</strong> 不匹配，导致资源打满或新连接被拒</td><td>结合压测与机器资源逐步上调；同时关注 CPU/内存与 GC/线程模型（以网关实现为准）</td></tr></tbody></table><p>说明：</p><ul><li>**“报文拦截”**在不同环境可能由多种策略触发（访问控制、WAF、上游代理限制、网关自身限额/超时）。如果现象与大报文、慢链路强相关，优先从 <strong>读取/写入/空闲超时</strong> 与 <strong>请求头上限</strong> 排查更高效。</li><li>调参后若需要快速生效，建议对目标实例执行一次 <strong>网关重载</strong>（或按你们的发布链路执行）。</li></ul><hr><h2 id="导入与导出建议" tabindex="-1">导入与导出建议 <a class="header-anchor" href="#导入与导出建议" aria-label="Permalink to &quot;导入与导出建议&quot;">​</a></h2><ul><li><strong>导出</strong>：在变更前导出作为备份；或用于从测试环境同步到生产前的“配置快照”。</li><li><strong>导入</strong>：用于批量初始化实例；导入后建议核对端口、证书、外部依赖地址等环境差异项，并执行一次 <strong>网关重载</strong>（若需要）。</li></ul><hr><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><table tabindex="0"><thead><tr><th>现象</th><th>可能原因与处理</th></tr></thead><tbody><tr><td>提示先选择实例</td><td>工具栏/导出等操作依赖目标行：请先勾选或单击选中实例。</td></tr><tr><td>实例显示离线/不健康</td><td>检查实例进程是否运行、心跳链路是否正常、端口是否被占用；必要时尝试启动并观察日志。</td></tr><tr><td>保存配置后未生效</td><td>可能需要执行 <strong>网关重载</strong> 或等待配置发布链路完成；检查是否保存到了正确实例。</td></tr><tr><td>导入失败或导入后异常</td><td>常见为环境差异（端口冲突、证书不匹配、依赖地址不同）；建议先在测试环境验证导入文件。</td></tr></tbody></table>',56)])])}const q=r(i,[["render",h]]);export{T as __pageData,q as default};
